A callable defined in python that returns a `bool` and that is passed into the `C++` code will return always true. Minimal example:

```c++
#include <pybind11/pybind11.h>
#include <pybind11/functional.h>

namespace py = pybind11;

#include <iostream>
#include <functional>

void forward(std::function<bool(int)> fn){
    std::cout << "21 -> " << fn(21) << std::endl;
    std::cout << "42 -> " << fn(42) << std::endl;
    std::cout << "84 -> " << fn(84) << std::endl;
}

PYBIND11_PLUGIN(bindings) {
    py::module m("bindings", "My C++ bindings.");
    m.def("forward", forward);
    return m.ptr();
}
```

